def category_report(records):
    """Return ``(category, count, total)`` rows, sorted by total, highest first.

    Ties on total break alphabetically by category, matching
    :func:`top_categories`.
    """
    stats = {}
    for r in records:
        count, total = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, total + r["duration"])
    rows = [(category, count, total) for category, (count, total) in stats.items()]
    return sorted(rows, key=lambda row: (-row[2], row[0]))


